import{_ as e,c as a,o as t,a5 as s}from"./chunks/framework.C2QCpDA7.js";const o="/images/engines/lesli/lesli.excalidraw.svg",b=JSON.parse('{"title":"Lesli","description":"","frontmatter":{},"headers":[],"relativePath":"engines/lesli/about/lesli.md","filePath":"engines/lesli/about/lesli.md","lastUpdated":1720403975000}'),i={name:"engines/lesli/about/lesli.md"},l=s('<h1 id="lesli" tabindex="-1">Lesli <a class="header-anchor" href="#lesli" aria-label="Permalink to &quot;Lesli&quot;">​</a></h1><p>Lesli is a SaaS Development Framework designed to build highly scalable, secure and customizable software products.</p><p>Built-on top of Ruby on Rails, Postgres, Vuejs, Bulma, SASS and many more awesome open-source libraries, packages, gems and tools.</p><p>Lesli provides a set of powerful features and can be extended through modules and provide a standard process to easely create custom modules.</p><blockquote><p>Lesli goes beyond being just a starter-kit or template. Lesli is a Ruby on Rails-based core gem that you can use to build modules (a.k.a. engines) leveraging its robust set of modules, built-in features, generators, components, and industry standards. With Lesli, you have the flexibility to extend existing functionalities or develop fully customized software tailored to your specific needs.</p></blockquote><h2 id="why-lesli" tabindex="-1">Why Lesli? <a class="header-anchor" href="#why-lesli" aria-label="Permalink to &quot;Why Lesli?&quot;">​</a></h2><p>Lesli is completely open source and comes with features and tools that can save you years of development effort, additionally, our pre-built modules can seamlessly extend Lesli&#39;s functionality, allowing you to build your own SaaS in a matter of minutes.</p><p>Leslie is published under the General Public License version 3, which means you are free to use, copy, redistribute it and/or modify Lesli (under the terms of the GNU General Public License).</p><h2 id="how-it-works" tabindex="-1">How it works? <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works?&quot;">​</a></h2><img alt="Lesli architecture" src="'+o+'"><h2 id="ruby-on-rails" tabindex="-1">Ruby on Rails <a class="header-anchor" href="#ruby-on-rails" aria-label="Permalink to &quot;Ruby on Rails&quot;">​</a></h2><p>Ruby on Rails, often referred to as Rails, is a popular open-source web application framework written in the Ruby programming language. It follows the Model-View-Controller (MVC) architectural pattern, providing developers with a structured and efficient way to build web applications.</p><p>By utilizing Ruby on Rails as the underlying framework, the SaaS development framework benefits from its extensive libraries, conventions, and built-in features. Rails simplifies common web development tasks, such as routing, database management, and handling user authentication, enabling developers to focus on building the core functionalities of their SaaS applications efficiently.</p><h2 id="saas-framework" tabindex="-1">SaaS Framework <a class="header-anchor" href="#saas-framework" aria-label="Permalink to &quot;SaaS Framework&quot;">​</a></h2><p>In the context of SaaS development, the framework leverages Ruby on Rails to create scalable and customizable software solutions that can be accessed by users over the internet. SaaS refers to a software delivery model where applications are centrally hosted and provided as a service to customers. This eliminates the need for users to install and maintain software locally, as they can access the application through a web browser.</p>',15),r=[l];function n(d,u,c,h,p,m){return t(),a("div",null,r)}const y=e(i,[["render",n]]);export{b as __pageData,y as default};
